// Calcula qué tan "parecido" es otro producto en medidas (volumen ±50%, o al menos una medida coincide)
function relacionados(prod, todos) {
  if (!tiene(prod.largo) || !tiene(prod.ancho) || !tiene(prod.alto)) return [];
  const volRef = prod.largo * prod.ancho * prod.alto;
  return todos
    .filter(p => p.id !== prod.id && tiene(p.largo) && tiene(p.ancho) && tiene(p.alto))
    .map(p => {
      const vol = p.largo * p.ancho * p.alto;
      const pctDiff = Math.abs(vol - volRef) / volRef;
      // coincidencia exacta en alguna dimensión (±2 cm)
      const dimMatch = [
        Math.abs(p.largo - prod.largo) <= 2,
        Math.abs(p.ancho - prod.ancho) <= 2,
        Math.abs(p.alto  - prod.alto)  <= 2,
      ].filter(Boolean).length;
      return { ...p, _score: dimMatch * 2 + (pctDiff < 0.5 ? 1 : 0) };
    })
    .filter(p => p._score > 0)
    .sort((a, b) => b._score - a._score)
    .slice(0, 8);
}

