function GaleriaSwipe({ imagenes, nombre }) {
  const [idx, setIdx] = useState(0);
  const touchStartX = useRef(null);
  const touchStartY = useRef(null);
  const fotos = imagenes && imagenes.length > 0 ? imagenes : [null];

  const prev = () => setIdx(i => (i - 1 + fotos.length) % fotos.length);
  const next = () => setIdx(i => (i + 1) % fotos.length);

  const onTouchStart = (e) => {
    touchStartX.current = e.touches[0].clientX;
    touchStartY.current = e.touches[0].clientY;
  };
  const onTouchEnd = (e) => {
    if (touchStartX.current === null) return;
    const dx = e.changedTouches[0].clientX - touchStartX.current;
    const dy = Math.abs(e.changedTouches[0].clientY - touchStartY.current);
    if (Math.abs(dx) > 40 && dy < 60) { dx < 0 ? next() : prev(); }
    touchStartX.current = null;
  };

  return (
    <div style={{ position: "relative", height: 260, background: "linear-gradient(135deg,#faf7f4,#f0ede8)", borderRadius: "20px 20px 0 0", overflow: "hidden", userSelect: "none" }}
      onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}>

      {/* Fotos con transición */}
      <div style={{ display: "flex", height: "100%", transition: "transform .3s cubic-bezier(.22,1,.36,1)", transform: `translateX(-${idx * 100}%)`, width: `${fotos.length * 100}%` }}>
        {fotos.map((src, i) => (
          <div key={i} style={{ width: `${100 / fotos.length}%`, height: "100%", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
            {src
              ? <img src={src} alt={`${nombre} ${i + 1}`} style={{ width: "100%", height: "100%", objectFit: "cover" }} draggable={false} />
              : <BoxSVG size={110} color={ORANGE} />}
          </div>
        ))}
      </div>

      {/* Puntos indicadores */}
      {fotos.length > 1 && (
        <div style={{ position: "absolute", bottom: 12, left: 0, right: 0, display: "flex", justifyContent: "center", gap: 6 }}>
          {fotos.map((_, i) => (
            <div key={i} onClick={() => setIdx(i)} style={{ width: i === idx ? 20 : 7, height: 7, borderRadius: 99, background: i === idx ? "#fff" : "rgba(255,255,255,.5)", cursor: "pointer", transition: "all .25s", boxShadow: "0 1px 4px rgba(0,0,0,.3)" }} />
          ))}
        </div>
      )}

      {/* Contador foto X/N */}
      {fotos.length > 1 && (
        <div style={{ position: "absolute", top: 12, right: 50, background: "rgba(0,0,0,.45)", color: "#fff", fontSize: 11, fontWeight: 700, padding: "3px 9px", borderRadius: 99 }}>
          {idx + 1} / {fotos.length}
        </div>
      )}
    </div>
  );
}

