export default function App() {
  const [productos, setProductos] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [usandoDemo, setUsandoDemo] = useState(false);
  const [cat, setCat]             = useState("Todos");
  const [carrito, setCarrito]     = useState([]);
  const [panel, setPanel]         = useState(false);
  const [added, setAdded]         = useState(null);
  const [detalle, setDetalle]     = useState(null);
  const [form, setForm]           = useState({ nombre:"", telefono:"", entrega:"tienda", colonia:"", direccion:"", estado:"", ciudad:"" });
  const [ferr, setFerr]           = useState("");

  useEffect(()=>{
    fetch(`${SUPABASE_URL}/rest/v1/productos?activo=eq.true&stock=gt.0&order=categoria,nombre`,
      {headers:{apikey:SUPABASE_KEY,Authorization:`Bearer ${SUPABASE_KEY}`}})
      .then(r=>r.json())
      .then(d=>{ if(d&&d.length>0){setProductos(d);}else{setProductos(DEMO);setUsandoDemo(true);} setLoading(false); })
      .catch(()=>{setProductos(DEMO);setUsandoDemo(true);setLoading(false);});
  },[]);

  const cats      = ["Todos",...Array.from(new Set(productos.map(p=>p.categoria).filter(Boolean)))];
  const filtrados = cat==="Todos"?productos:productos.filter(p=>p.categoria===cat);
  const totalItems = carrito.reduce((s,i)=>s+i.qty,0);
  const total      = carrito.reduce((s,i)=>s+i.precio*i.qty,0);
  const envioGratis = form.entrega==="cdmx"&&total>=ENVIO_GRATIS_MIN;

  const agregar=(prod)=>{
    setCarrito(prev=>{
      const ex=prev.find(i=>i.id===prod.id);
      if(ex){if(ex.qty>=prod.stock)return prev;return prev.map(i=>i.id===prod.id?{...i,qty:i.qty+1}:i);}
      return [...prev,{...prod,qty:1}];
    });
    setAdded(prod.id); setTimeout(()=>setAdded(null),700);
  };
  const cambiarQty=(id,d)=>setCarrito(prev=>prev.map(i=>i.id===id?{...i,qty:i.qty+d}:i).filter(i=>i.qty>0));
  const setF=(k)=>(e)=>setForm(f=>({...f,[k]:e.target.value}));
  const handleWa=()=>{
    if(!form.nombre.trim()){setFerr("Por favor ingresa tu nombre.");return;}
    if(!/^\d{10,}$/.test(form.telefono.replace(/\s/g,""))){setFerr("Ingresa un teléfono válido (10 dígitos mínimo).");return;}
    if(form.entrega==="foraneo"&&!form.estado){setFerr("Selecciona el estado de destino.");return;}
    setFerr("");
    window.open(`https://wa.me/${WA_NUMBER}?text=${buildMsg(carrito,form,total)}`,"_blank");
  };

  return(<>
    <style>{css}</style>
    {usandoDemo&&<div style={{background:"#fff7ed",borderBottom:"1px solid #fed7aa",padding:"8px 20px",textAlign:"center",fontSize:12,fontWeight:600,color:"#9a3412"}}>👀 Vista previa con productos de ejemplo — conecta Supabase para ver tus productos reales</div>}

    <header className="hdr"><div className="hdr-in">
      <div className="logo">
        <svg viewBox="0 0 44 44" fill="none"><path d="M22 6L38 14V30L22 38L6 30V14L22 6Z" stroke="#1a1a1a" strokeWidth="2.2" fill="none"/><path d="M22 6V38M6 14L22 22L38 14" stroke="#1a1a1a" strokeWidth="2.2"/><path d="M14 9.5L30 17.5" stroke="#E8681A" strokeWidth="1.8" strokeDasharray="2.5 2.5"/></svg>
        <span className="logo-txt"><span className="l1">TODO EN</span><span className="l2"><span className="lc">CAJAS</span><span className="lo">.COM</span></span></span>
      </div>
      <button className="cart-btn" onClick={()=>setPanel(true)}><CartIco/> Carrito {totalItems>0&&<span className="badge">{totalItems}</span>}</button>
    </div></header>

    <section className="hero">
      <h1>Cajas y empaque<br/><span>directo a tu puerta</span></h1>
      <p>Material de empaque para tu negocio. Stock en tiempo real, precios justos y atención por WhatsApp.</p>
      <div className="trust">
        {[`🚚 Envío gratis CDMX desde ${fmt(ENVIO_GRATIS_MIN)}`,"🏪 Recolección en tienda","📦 Envíos foráneos","💬 Atención por WhatsApp"]
          .map(t=><div className="ti" key={t}><div className="td"/>{t}</div>)}
      </div>
    </section>

    <main className="main">
      {!loading&&<div className="filters">{cats.map(c=><button key={c} className={`fb${cat===c?" act":""}`} onClick={()=>setCat(c)}>{c}</button>)}</div>}
      {loading&&<div className="load"><div className="spin"/>Cargando productos...</div>}
      {!loading&&filtrados.length>0&&(<>
        <div className="sec">{filtrados.length} producto{filtrados.length!==1?"s":""} disponible{filtrados.length!==1?"s":""}</div>
        <div className="grid">
          {filtrados.map(prod=>(
            <div className="card" key={prod.id}>
              <div className="cimg">
                {prod.imagenes&&prod.imagenes.length>0?<img src={prod.imagenes[0]} alt={prod.nombre}/>:<BoxSVG size={58}/>}
                {prod.categoria&&<span className="ctag">{prod.categoria}</span>}
              </div>
              <div className="cbody">
                <div className="cname">{prod.nombre}</div>
                <div className="csku">SKU: {prod.sku}</div>
                <div className={`cstock${prod.stock<=5?" low":""}`}>{prod.stock<=5?`⚠ Solo ${prod.stock} pzas`:`✓ ${prod.stock} pzas disponibles`}</div>
                <button className="detalle-btn" onClick={()=>setDetalle(prod)}>Ver detalles →</button>
                <div className="cfoot">
                  <div className="cprice">{fmt(prod.precio)} <span>c/u</span></div>
                  <button className={`add${added===prod.id?" done":""}`} onClick={()=>{agregar(prod);setPanel(true);}}>{added===prod.id?"✓":"+"}</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </>)}
    </main>

    <footer><div className="fl">TODO EN <span>CAJAS</span>.COM</div><p>CDMX · Empaque profesional para tu negocio<br/>WhatsApp: 55 2268 8744</p></footer>

    {detalle&&<ModalDetalles
      prod={detalle}
      todos={productos}
      onClose={()=>setDetalle(null)}
      onAgregar={(p)=>{agregar(p);setPanel(true);}}
      onVerDetalle={(p)=>setDetalle(p)}
      enCarrito={carrito.some(i=>i.id===detalle.id)}
    />}

    {panel&&(<>
      <div className="ov" onClick={()=>setPanel(false)}/>
      <aside className="panel">
        <div className="ph"><h2>🛒 Tu pedido</h2><button className="closebtn" onClick={()=>setPanel(false)}>✕</button></div>
        <div className="pb">
          {carrito.length===0?(<div className="empty"><BoxSVG size={52} color="#ddd"/><p style={{marginTop:12}}>Tu carrito está vacío</p><p style={{fontSize:13,marginTop:6,fontWeight:400,color:"#bbb"}}>Agrega productos para continuar</p></div>):(<>
            {carrito.map(item=>(
              <div className="ci" key={item.id}>
                <div className="ci-ic">{item.imagenes&&item.imagenes.length>0?<img src={item.imagenes[0]} alt={item.nombre}/>:<BoxSVG size={22}/>}</div>
                <div className="ci-info"><div className="ci-name">{item.nombre}</div><div className="ci-price">{fmt(item.precio)} c/u</div></div>
                <div className="qty">
                  <button className="qb" onClick={()=>cambiarQty(item.id,-1)}>−</button>
                  <span className="qn">{item.qty}</span>
                  <button className="qb" onClick={()=>cambiarQty(item.id,1)} disabled={item.qty>=item.stock}>+</button>
                </div>
                <span className="ci-tot">{fmt(item.precio*item.qty)}</span>
                <button className="ci-del" onClick={()=>setCarrito(c=>c.filter(i=>i.id!==item.id))}>✕</button>
              </div>
            ))}
            <div className="form">
              <div className="sec" style={{marginTop:8}}>Tus datos</div>
              <div><label className="lbl">Nombre completo</label><input className="inp" placeholder="Ej. Ana García" value={form.nombre} onChange={setF("nombre")}/></div>
              <div><label className="lbl">Teléfono</label><input className="inp" type="tel" placeholder="10 dígitos" value={form.telefono} onChange={setF("telefono")}/></div>
              <div>
                <label className="lbl">¿Cómo recibes tu pedido?</label>
                <div className="rg">
                  {[{v:"tienda",l:"🏪 Recoger en tienda"},{v:"cdmx",l:"🚚 Entrega CDMX"},{v:"foraneo",l:"📦 Envío foráneo"}].map(o=>(
                    <div key={o.v} className={`ro${form.entrega===o.v?" sel":""}`} onClick={()=>setForm(f=>({...f,entrega:o.v}))}><div className="rc"/>{o.l}</div>
                  ))}
                </div>
              </div>
              <EnvioInfo entrega={form.entrega} total={total}/>
              {form.entrega==="cdmx"&&(<>
                <div><label className="lbl">Colonia / Alcaldía</label><input className="inp" placeholder="Ej. Roma Norte" value={form.colonia} onChange={setF("colonia")}/></div>
                <div><label className="lbl">Dirección</label><input className="inp" placeholder="Calle, número, referencias" value={form.direccion} onChange={setF("direccion")}/></div>
              </>)}
              {form.entrega==="foraneo"&&(<>
                <div><label className="lbl">Estado de destino *</label>
                  <select className="inp" value={form.estado} onChange={setF("estado")}><option value="">Selecciona un estado…</option>{ESTADOS_MX.map(e=><option key={e} value={e}>{e}</option>)}</select></div>
                <div><label className="lbl">Ciudad / Código Postal</label><input className="inp" placeholder="Ej. Monterrey, 64000" value={form.ciudad} onChange={setF("ciudad")}/></div>
              </>)}
              {ferr&&<div className="ferr">⚠ {ferr}</div>}
            </div>
          </>)}
        </div>
        <div className="pf">
          {carrito.length>0&&(<>
            <div className="sub"><span className="sub-lbl">Subtotal productos</span><span className="sub-amt">{fmt(total)}</span></div>
            <div className="sub-note" style={{color:envioGratis?"#22c55e":form.entrega==="tienda"?"#888":"#aaa"}}>
              {envioGratis?"🎉 + Envío gratis":form.entrega==="tienda"?"🏪 Sin costo de envío":"📋 + Envío: se cotiza por WhatsApp"}
            </div>
          </>)}
          <button className="wa" onClick={handleWa} disabled={carrito.length===0}>
            <WA/>{carrito.length===0?"Agrega productos para continuar":"Confirmar pedido por WhatsApp"}
          </button>
          {carrito.length>0&&<p style={{fontSize:11,color:"#aaa",textAlign:"center",marginTop:7}}>Se abrirá WhatsApp con los detalles completos</p>}
        </div>
      </aside>
    </>)}
  </>);
}
